这是一个使用 C++ 和 CUDA 编写的完整示例。

在这个场景中，我们将模拟一个**参数服务器（Parameter Server）**的简化模型：

1.  **父进程（Server）：** 持有“权重（Weights）”的原始数据，并在 GPU 上分配显存。
2.  **子进程（Worker）：** 通过 IPC 获取显存句柄，直接在父进程的显存上运行 CUDA Kernel 进行**权重更新**。

**核心亮点：** 子进程修改数据时，**没有发生任何显存拷贝**，它直接修改了父进程持有的那块物理显存。

### 代码实现 (`ipc_weight_update.cu`)

请将以下代码保存为 `.cu` 文件。

```cpp
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/socket.h>
#include <sys/wait.h>
#include <cuda_runtime.h>

// 简单的 CUDA Kernel：模拟权重更新 (SGD)
// weights: 指向显存的指针
// lr: 学习率
// N: 元素个数
__global__ void update_weights_kernel(float *weights, float lr, int N) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx < N) {
        // 模拟更新： Weight_new = Weight_old + lr
        // 这里为了演示明显，我们直接做加法
        weights[idx] = weights[idx] + lr;
    }
}

// 检查 CUDA 错误的辅助函数
#define CHECK_CUDA(call) { \
    cudaError_t err = call; \
    if (err != cudaSuccess) { \
        printf("CUDA Error: %s at line %d\n", cudaGetErrorString(err), __LINE__); \
        exit(1); \
    } \
}

int main() {
    int sv[2]; // 用于传递 Handle 的 socket pair
    if (socketpair(AF_UNIX, SOCK_STREAM, 0, sv) < 0) {
        perror("socketpair");
        exit(1);
    }

    int N = 10; // 权重数量
    size_t size = N * sizeof(float);

    pid_t pid = fork();

    if (pid == 0) { 
        // ==========================================
        // 子进程 (Worker): 负责更新权重
        // ==========================================
        close(sv[0]); // 关闭读端（我们这里约定 sv[1] 用来交互，其实 socket 是双向的）

        // 1. 设置设备 (必须在任何 CUDA 调用前设置，且父子进程通常使用同一个 GPU ID)
        CHECK_CUDA(cudaSetDevice(0));

        // 2. 接收 Handle
        cudaIpcMemHandle_t ipc_handle;
        read(sv[1], &ipc_handle, sizeof(cudaIpcMemHandle_t));
        printf("[Child] 收到 IPC Handle。\n");

        // 3. 打开 Handle，映射显存
        float *d_weights_mapped;
        // flag 使用 cudaIpcMemLazyEnablePeerAccess 可以按需建立映射
        CHECK_CUDA(cudaIpcOpenMemHandle((void **)&d_weights_mapped, ipc_handle, cudaIpcMemLazyEnablePeerAccess));
        printf("[Child] 映射显存成功，准备运行 Kernel 更新权重...\n");

        // 4. 运行 Kernel 直接修改父进程的显存
        // 这里的 d_weights_mapped 指向的物理地址和父进程的 d_weights 是一样的
        update_weights_kernel<<<1, N>>>(d_weights_mapped, 0.5f, N);

        // 5. 同步并检查错误
        CHECK_CUDA(cudaDeviceSynchronize());
        printf("[Child] 权重更新完成 (每个元素 +0.5)。\n");

        // 6. 清理：关闭 Handle
        CHECK_CUDA(cudaIpcCloseMemHandle(d_weights_mapped));

        // 通知父进程我完事了 (发送一个简单的字节)
        char ack = 'K';
        write(sv[1], &ack, 1);
        close(sv[1]);
        exit(0);

    } else {
        // ==========================================
        // 父进程 (Server): 持有权重
        // ==========================================
        close(sv[1]); // 关闭写端

        CHECK_CUDA(cudaSetDevice(0));

        // 1. 分配显存
        float *d_weights;
        CHECK_CUDA(cudaMalloc((void **)&d_weights, size));

        // 2. 初始化权重 (例如全为 1.0)
        float *h_weights = (float*)malloc(size);
        for(int i=0; i<N; i++) h_weights[i] = 1.0f;

        CHECK_CUDA(cudaMemcpy(d_weights, h_weights, size, cudaMemcpyHostToDevice));
        printf("[Parent] 显存已分配并初始化为 1.0。\n");

        // 3. 获取 IPC Handle
        cudaIpcMemHandle_t ipc_handle;
        CHECK_CUDA(cudaIpcGetMemHandle(&ipc_handle, d_weights));

        // 4. 发送 Handle 给子进程
        write(sv[0], &ipc_handle, sizeof(cudaIpcMemHandle_t));
        printf("[Parent] Handle 已发送给子进程。\n");

        // 5. 等待子进程完成 (实际项目中应该使用 IPC Event 或其他信号机制)
        char ack;
        read(sv[0], &ack, 1); // 阻塞等待子进程

        // 6. 验证结果
        // 把 GPU 的数据读回 CPU 看看是不是被改了
        CHECK_CUDA(cudaMemcpy(h_weights, d_weights, size, cudaMemcpyDeviceToHost));

        printf("[Parent] 读取更新后的权重:\n");
        for(int i=0; i<N; i++) {
            printf("%.1f ", h_weights[i]); // 应该输出 1.5 (1.0 + 0.5)
        }
        printf("\n");

        // 7. 清理
        CHECK_CUDA(cudaFree(d_weights));
        free(h_weights);
        close(sv[0]);
        wait(NULL); // 等待子进程彻底退出
    }

    return 0;
}
```

### 编译与运行

假设你已经安装了 CUDA Toolkit (nvcc)：

```bash
# 编译
nvcc ipc_weight_update.cu -o ipc_test

# 运行
./ipc_test
```

### 预期输出结果

```text
[Parent] 显存已分配并初始化为 1.0。
[Parent] Handle 已发送给子进程。
[Child] 收到 IPC Handle。
[Child] 映射显存成功，准备运行 Kernel 更新权重...
[Child] 权重更新完成 (每个元素 +0.5)。
[Parent] 读取更新后的权重:
1.5 1.5 1.5 1.5 1.5 1.5 1.5 1.5 1.5 1.5 
```

### 代码关键点解析

1.  **`socketpair` 与 `fork`**：
    *   为了模拟两个进程，我们使用了 `fork`。
    *   为了在父子进程间传递那个 64 字节的 `cudaIpcMemHandle_t`，我们使用了最简单的 `socketpair`（UNIX 域套接字）。

2.  **`cudaIpcGetMemHandle` (父进程)**：
    *   在父进程调用 `cudaMalloc` 后，我们将这个指针转换成了一个可传输的 Handle。
    *   **注意**：此时显存并没有移动，Handle 只是一个“通行证”。

3.  **`cudaIpcOpenMemHandle` (子进程)**：
    *   子进程拿到通行证，调用 Open。
    *   此时，`d_weights_mapped` 指针在子进程的虚拟地址空间中是有效的，但它**物理上指向**父进程申请的那块显存。

4.  **Zero Copy (零拷贝)**：
    *   在 `update_weights_kernel` 中，子进程直接读写显存。数据**没有**经过 CPU，也**没有**在两块显存之间复制。

### 进阶提示：如果在循环训练中怎么做？

上面的代码只跑了一次。如果在深度学习训练循环中（比如每秒更新 100 次），**绝对不要**把 `cudaIpcOpenMemHandle`
